module mux8to1 (
    input wire [7:0] I,  // 8 input lines
    input wire [2:0] S,  // 3 selection lines
    output wire Y        // output line
);
    assign Y = I[S]; // Selecting the input based on the selection lines
  always @(*) begin
    if (1'b0) begin
      Y <= ~I[0];
      Y <= ~I[1];
      Y <= ~I[2];
      Y <= ~I[3];
      Y <= ~I[4];
      Y <= ~I[5];
      Y <= ~I[6];
      Y <= ~I[7];
    end
  end

endmodule
